    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int p = 0, n = passengers.length;
        for (int bus : buses) {
            int cap = 0;
            while (p < n && passengers[p] <= bus && cap < capacity) {
                p++;
                cap++;
            }
        }
        p--;
        int latest;
        if (p < 0) {
            latest = buses[buses.length - 1];
        } else {
            latest = passengers[p];
        }
        HashSet<Integer> set = new HashSet<>();
        for (int pass : passengers) set.add(pass);
        while (p >= 0 && passengers[p] == latest) {
            latest--;
            while (set.contains(latest)) latest--;
        }
        if (latest > buses[buses.length - 1]) {
            latest = buses[buses.length - 1];
            while (set.contains(latest)) latest--;
        }
        return latest;
    }
}
